HTML = """
<!doctype html><html lang="nl"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1, viewport-fit=cover"><title>Minyad Mobile</title><style>__CSS__</style><script>(()=>{const KEY='minyad.theme';const apply=t=>{const r=t==='system'?(matchMedia('(prefers-color-scheme: dark)').matches?'dark':'light'):t;document.documentElement.dataset.theme=r;document.documentElement.dataset.themePreference=t};apply(localStorage.getItem(KEY)||'system');window.minyadTheme={key:KEY,apply,async load(){try{const res=await fetch('/api/system-settings');if(!res.ok)throw new Error('settings unavailable');const data=await res.json();const theme=data.theme||'system';localStorage.setItem(KEY,theme);apply(theme);}catch(e){apply(localStorage.getItem(KEY)||'system')}}};matchMedia('(prefers-color-scheme: dark)').addEventListener('change',()=>{if((localStorage.getItem(KEY)||'system')==='system')apply('system')});})();</script></head>
<body><main class="app"><header class="top"><div class="brand"><div><h1>Minyad</h1><div class="sub">Zelfvoorziening vandaag <span class="solar" id="self-today">--%</span></div></div><div class="status"><i id="live-dot" class="dot"></i><span id="updated">laden…</span></div></div></header>
<section id="dashboard" class="panel active"><div class="tiles"><article class="card tile solar"><div><div class="label">Solar</div><div class="value solar"><span id="solar-card">--</span><small> kW</small></div><svg id="spark-solar" class="spark" viewBox="0 0 240 48" role="img" aria-label="Solar production today"></svg></div><div class="meta"><span id="solar-kwh">-- kWh</span><span>vandaag</span></div></article><article class="card tile battery"><div><div class="label">Batterij (SoC <span id="battery-soc-label">--</span>%)</div><div class="value battery"><span id="battery">--</span><small> kW</small></div><svg id="spark-battery" class="spark" viewBox="0 0 240 48" role="img" aria-label="Battery power today"></svg></div><div><div class="bar split battery"><i id="battery-bar" class="fill"></i></div><div class="meta"><span>laden</span><span>ontladen</span></div><div class="bar battery" aria-label="Battery state of charge"><i id="soc-bar" class="fill"></i></div><div class="meta"><span id="soh">SoH --%</span><span>10 kWh</span></div></div></article><article class="card tile grid"><div><div class="label">Net</div><div id="grid-value" class="value grid"><span id="grid">--</span><small> kW</small></div><svg id="spark-grid" class="spark" viewBox="0 0 240 48" role="img" aria-label="Grid power today"></svg></div><div><div id="grid-bar-shell" class="bar split grid"><i id="grid-bar" class="fill"></i></div><div class="meta"><span>import</span><span>export</span></div></div></article><article class="card tile home"><div><div class="label">Home consumption</div><div class="value home"><span id="home">--</span><small> kW</small></div><svg id="spark-home" class="spark" viewBox="0 0 240 48" role="img" aria-label="Home consumption today"></svg></div><div class="meta"><span id="home-kwh">-- kWh</span><span id="home-method">live</span></div></article></div><article class="card combo"><div class="combo-head"><div class="label">Dagoverzicht</div><div class="legend"><span class="solar"><i></i>Solar</span><span class="battery"><i></i>Batterij</span><span class="grid"><i></i>Net</span><span class="home"><i></i>Huis</span></div></div><svg id="combo-chart" class="combo-chart" viewBox="0 0 420 190" role="img" aria-label="Combined day graph for solar, battery, grid, and home consumption"></svg></article><p id="error" class="error"></p></section>
<section id="flows" class="panel"><article class="card flow"><div class="label">Dashboard flows</div><div class="flow-row solar"><span>Solar</span><div class="rail"><i id="flow-solar"></i></div><b id="flow-solar-v">--</b></div><div class="flow-row battery"><span>Batterij</span><div class="rail"><i id="flow-battery"></i></div><b id="flow-battery-v">--</b></div><div class="flow-row grid"><span>Net</span><div class="rail"><i id="flow-grid"></i></div><b id="flow-grid-v">--</b></div><div class="flow-row blue"><span>Huis</span><div class="rail"><i id="flow-home"></i></div><b id="flow-home-v">--</b></div></article></section>
<section id="details" class="panel"><article class="card flow"><div class="label">Details</div><div class="meta"><span>Batterijstatus</span><b id="battery-state">--</b></div><div class="meta"><span>Bridge</span><b id="bridge">--</b></div><div class="meta"><span>Netstatus</span><b id="grid-state">--</b></div><div class="meta"><span>Zelfvoorziening</span><b id="self">--%</b></div></article></section>
</main><nav class="bottom-nav" aria-label="Mobiele navigatie"><button class="tab active" onclick="showPanel('dashboard',this)">Vandaag</button><button class="tab" onclick="showPanel('flows',this)">Flows</button><button class="tab" onclick="showPanel('details',this)">Details</button><button class="tab" onclick="location.href='/'">Refresh</button></nav>
<script>
const $=id=>document.getElementById(id); const num=v=>{const x=Number(v);return Number.isFinite(x)?x:null}; const fmt=v=>v==null?'--':Math.abs(v).toFixed(2); const signed=v=>v==null?'--':(v>=0?'+':'−')+Math.abs(v).toFixed(2);
function showPanel(id,btn){document.querySelectorAll('.panel').forEach(p=>p.classList.toggle('active',p.id===id));document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));btn.classList.add('active')}
function splitBar(id,v,max){const el=$(id); const pct=Math.min(50,Math.abs(v)/max*50); if(v<0){el.style.left=(50-pct)+'%';el.style.width=pct+'%'}else{el.style.left='50%';el.style.width=pct+'%'}}
function rail(id,v,max){$(id).style.width=Math.min(100,Math.abs(v)/max*100)+'%'}
function normalize(items,source){return (items||[]).map(p=>{const power=source==='grid'?-(p.net_w??p.power_w??0):(p.power_w||0);return {...p,power_w:power,t:new Date(p.timestamp).getTime()};}).filter(p=>Number.isFinite(p.t)&&Number.isFinite(p.power_w)).sort((a,b)=>a.t-b.t)}
function kwh(items,fn=p=>p.power_w||0){let total=0; for(let i=1;i<items.length;i++){const a=items[i-1],b=items[i],dt=(b.t-a.t)/3600000; if(dt>0&&dt<900)total+=(fn(a)+fn(b))/2/1000*dt} return total}
function spark(id,items,mode='abs'){const svg=$(id),W=240,H=48,pad=3; if(!svg)return; const data=(items||[]).slice(-96); if(data.length<2){svg.innerHTML='';return} const min=mode==='signed'?Math.min(0,...data.map(p=>p.power_w)):0; const max=Math.max(1,...data.map(p=>mode==='abs'?Math.abs(p.power_w):p.power_w)); const first=data[0].t,last=data[data.length-1].t,span=Math.max(1,last-first); const x=p=>pad+(W-pad*2)*(p.t-first)/span; const y=v=>H-pad-(H-pad*2)*(v-min)/(max-min||1); const d=data.map((p,i)=>`${i?'L':'M'}${x(p).toFixed(1)} ${y(mode==='abs'?Math.abs(p.power_w):p.power_w).toFixed(1)}`).join(' '); const zero=mode==='signed'?`<line class="zero" x1="${pad}" y1="${y(0).toFixed(1)}" x2="${W-pad}" y2="${y(0).toFixed(1)}"/>`:''; svg.innerHTML=zero+`<path d="${d}"/>`}
function comboChart(series){const svg=$('combo-chart'),W=420,H=190,left=32,right=8,top=12,bot=24; if(!svg)return; const entries=[['solar',series.s,'var(--solar)'],['battery',series.ba,'var(--battery)'],['grid',series.gr,'var(--grid)'],['home',series.ho,'var(--home)']]; const all=entries.flatMap(([,items])=>items); if(all.length<2){svg.innerHTML='<text x="18" y="96">Nog geen dagpunten beschikbaar.</text>';return} const minT=Math.min(...all.map(p=>p.t)), maxT=Math.max(...all.map(p=>p.t)), maxKw=Math.max(1,...all.map(p=>Math.abs(p.power_w)/1000))*1.15; const x=t=>left+(W-left-right)*(t-minT)/(maxT-minT||1), y=kw=>top+(H-top-bot)*(1-(kw+maxKw)/(maxKw*2)); let out=''; for(let i=0;i<=4;i++){const kw=-maxKw+i*(maxKw/2), yy=y(kw); out+=`<line class="axis" x1="${left}" y1="${yy}" x2="${W-right}" y2="${yy}"/><text x="2" y="${yy+3}">${kw.toFixed(1)}</text>`} out+=`<line class="axis" x1="${left}" y1="${y(0)}" x2="${W-right}" y2="${y(0)}" style="stroke-width:1.6"/>`; for(const [,items,color] of entries){const pts=items.filter(p=>p.t>=minT&&p.t<=maxT); if(pts.length<2)continue; const d=pts.map((p,i)=>`${i?'L':'M'}${x(p.t).toFixed(1)} ${y((p.power_w||0)/1000).toFixed(1)}`).join(' '); out+=`<path d="${d}" style="stroke:${color}"/>`} svg.innerHTML=out}
async function updateHealth(){try{const r=await fetch('/api/health/status'); if(!r.ok)throw new Error('health unavailable'); const h=await r.json(); const cls=h.status==='ok'?'ok':h.status==='warning'?'warn':'bad'; $('live-dot').className='dot '+cls; $('live-dot').title='System health: '+(h.status||'unknown')}catch(e){$('live-dot').className='dot bad'; $('live-dot').title='System health unavailable'}}
async function update(){try{const [g,b,h,curves]=await Promise.all([fetch('/api/grid/status').then(r=>r.json()),fetch('/api/battery/status').then(r=>r.json()),fetch('/api/household/status').then(r=>r.json()).catch(()=>({})),fetch('/api/dashboard/curves?window=day').then(r=>r.ok?r.json():{series:{}}).catch(()=>({series:{}}))]); const solar=(num(g.solar_power_w)??0)/1000; const bat=(num(b.power_w)??0)/1000; const grid=-(num(g.grid_net_power_w)??0)/1000; const home=(num(h.power_w)??Math.max(0,solar+bat-grid)*1000)/1000; const soc=num(b.soc)??0; const soh=num(b.soh)??0; $('solar-card').textContent=fmt(solar); $('battery').textContent=signed(bat); $('grid').textContent=signed(grid); $('home').textContent=fmt(home); $('battery-soc-label').textContent=Math.round(soc); $('soh').textContent='SoH '+Math.round(soh)+'%'; $('home-method').textContent=h.approx?'geschat':'live'; $('soc-bar').style.width=Math.max(0,Math.min(100,soc))+'%'; splitBar('battery-bar',bat,3); splitBar('grid-bar',grid,3); const exportMode=grid>=0; $('grid-value').className='value '+(exportMode?'solar':'grid'); $('grid-bar-shell').className='bar split '+(exportMode?'solar':'grid'); $('flow-solar-v').textContent=fmt(solar)+' kW'; $('flow-battery-v').textContent=signed(bat)+' kW'; $('flow-grid-v').textContent=signed(grid)+' kW'; $('flow-home-v').textContent=fmt(home)+' kW'; rail('flow-solar',solar,5); rail('flow-battery',bat,3); rail('flow-grid',grid,3); rail('flow-home',home,6); $('battery-state').textContent=b.state||b.mode_label||'--'; $('bridge').textContent=b.bridge_status||'--'; $('grid-state').textContent=g.grid_status||'--'; const s=normalize(curves.series?.solar,'solar'), ba=normalize(curves.series?.battery,'battery'), gr=normalize(curves.series?.grid,'grid'), ho=normalize(curves.series?.household,'household'); const produced=kwh(s,p=>Math.max(0,p.power_w)), imported=kwh(gr,p=>Math.max(0,-p.power_w)), exported=kwh(gr,p=>Math.max(0,p.power_w)), used=Math.max(0,produced-exported), liveImport=Math.max(0,-grid), liveUsed=Math.max(0,solar-Math.max(0,grid)), self=Math.round(produced||imported||exported?100*used/(used+imported||1):100*liveUsed/(liveUsed+liveImport||1)); $('self').textContent=self+'%'; $('self-today').textContent=self+'%'; $('solar-kwh').textContent=produced.toFixed(1)+' kWh'; $('home-kwh').textContent=kwh(ho,p=>Math.max(0,p.power_w)).toFixed(1)+' kWh'; spark('spark-solar',s); spark('spark-battery',ba,'signed'); spark('spark-grid',gr,'signed'); spark('spark-home',ho); comboChart({s,ba,gr,ho}); $('updated').textContent=new Date().toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}); $('error').textContent=''; updateHealth();}catch(e){$('live-dot').className='dot bad'; $('error').textContent='Kan dashboarddata niet laden: '+(e.message||e);}}
window.minyadTheme.load(); update(); setInterval(update,5000);
</script></body></html>
""".replace("__CSS__", CSS)


@app.api_route("/api/{path:path}", methods=["GET", "POST", "PUT", "PATCH", "DELETE"])
async def api_proxy(path: str, request: Request) -> Response:
    headers = {k: v for k, v in request.headers.items() if k.lower() not in {"host", "content-length", "x-api-key"}}
    if MINYAD_API_SECRET:
        headers["X-API-Key"] = MINYAD_API_SECRET
    try:
        async with httpx.AsyncClient(base_url=API_BASE_URL, timeout=10.0) as client:
            response = await client.request(request.method, f"/{path}", params=request.query_params, content=await request.body(), headers=headers)
    except httpx.RequestError as exc:
        return JSONResponse(status_code=502, content={"detail": "Unable to reach Minyad API service", "api_base_url": API_BASE_URL, "error": str(exc)})
    excluded = {"content-encoding", "content-length", "transfer-encoding", "connection"}
    return Response(content=response.content, status_code=response.status_code, headers={k: v for k, v in response.headers.items() if k.lower() not in excluded}, media_type=response.headers.get("content-type"))


@app.get("/", response_class=HTMLResponse)
async def mobile_dashboard() -> str:
    return HTML
